+/// endpoints remain positive `i32`s on the wire. Mirrors MINIX 3
+/// `_ENDPOINT_MAX_GENERATION`.
+pub const ENDPOINT_MAX_GENERATION: GenNr = (1 << (31 - ENDPOINT_GEN_SHIFT)) - 1;
