905	+/// `SYS_FORK` — clone `parent` into the free slot `child_nr`; reply the
906	+/// child's endpoint.
907	+pub(super) fn do_fork(
908	+    proc_table: &mut [Proc; N_PROC_SLOTS],
909	+    caller_nr: ProcNr,
910	+    msg: &mut Message,
911	+) -> i32 {
912	+    let parent_e = read_i32(msg, 0);
913	+    let child_nr_raw = read_i32(msg, 4);
914	+
915	+    let parent_idx = match super::resolve_target(proc_table, caller_nr, parent_e) {
916	+        Ok(idx) => idx,
917	+        Err(e) => return e,
918	+    };
919	+
920	+    // The child slot is named by proc nr, not endpoint — it is free, so it
921	+    // has no live endpoint to validate. Task slots (negative) are never
922	+    // forkable.
923	+    if !(0..NR_PROCS as i32).contains(&child_nr_raw) {
924	+        return EINVAL;
925	+    }
926	+    let child_nr = ProcNr::new(child_nr_raw);
927	+    let child_idx = proc_index(child_nr).expect("user proc nr in range");
928	+    if proc_table[child_idx].rts_flags.load(Ordering::Relaxed) & RTS_SLOT_FREE == 0 {
929	+        return EINVAL;
930	+    }
931	+
932	+    // Parent gate: RECEIVE-blocked (mid-SENDREC to PM in the live flow) with
933	+    // its frame fully parked and no delivery half-done. MINIX 3 do_fork.c:
934	+    // "make sure the parent is blocked waiting for the reply".
935	+    let parent = &proc_table[parent_idx];
936	+    let parent_rts = parent.rts_flags.load(Ordering::Relaxed);
937	+    if parent_rts & RTS_RECEIVING == 0
938	+        || parent_rts & RTS_SENDING != 0
939	+        || parent.misc_flags & MF_DELIVERMSG != 0
940	+    {
941	+        return EINVAL;
942	+    }
943	+    if parent.ttbr0_pa == 0 {
944	+        // A proc with no address space (kernel task, never-loaded server)
945	+        // has nothing to clone.
946	+        return EINVAL;
947	+    }
948	+
949	+    // Build the child's address space *before* touching the child slot, so a
950	+    // mid-copy allocation failure needs no proc-table rollback.
951	+    let child_as = match copy_addrspace(parent.ttbr0_pa) {
952	+        Ok((ttbr0_pa, pages)) => (ttbr0_pa, pages),
953	+        Err(_) => return ENOMEM,
954	+    };
955	+    let (child_ttbr0, pages) = child_as;
956	+
957	+    // SAFETY: single-threaded EL1 context; sole accessor of the ASID pool.
958	+    let child_asid = unsafe { asid::alloc_asid() };
959	+
960	+    // Snapshot the parent fields the child inherits (ends the shared borrow
961	+    // before the child slot is borrowed mutably).
962	+    let p = &proc_table[parent_idx];
963	+    let parent_regs = p.regs;
964	+    let parent_priority = p.priority;
965	+    let parent_quantum_ms = p.quantum_ms;
966	+    let parent_getfrom_e = p.getfrom_e;
967	+    let parent_deliver_msg_vir = p.deliver_msg_vir;
968	+    let parent_heap_window = p.heap_window;
969	+    let parent_priv_id = p.priv_id;
970	+    let parent_name = p.name;
971	+    let parent_reply_pend = p.misc_flags & MF_REPLY_PEND;
972	+
973	+    let child_e = {
974	+        let c = &mut proc_table[child_idx];
975	+        // Inherited: the parent's exact resume state and identity-adjacent
976	+        // fields.
977	+        c.regs = parent_regs;
978	+        c.priv_id = parent_priv_id;
979	+        c.misc_flags = parent_reply_pend;
980	+        c.priority = parent_priority;
981	+        c.quantum_ms = parent_quantum_ms;
982	+        c.quantum_left = parent_quantum_ms as u64;
983	+        c.getfrom_e = parent_getfrom_e;
984	+        c.deliver_msg_vir = parent_deliver_msg_vir;
985	+        c.heap_window = parent_heap_window;
