1034	+/// Eagerly clone every mapped page of the tree rooted at `parent_ttbr0` into
1035	+/// a fresh address space: allocate a frame per leaf, copy the 4 KiB through
1036	+/// HHDM, and map it at the same VA with the parent's permissions (I-cache
1037	+/// synced for executable pages — TCG hides a missing flush, real hardware
1038	+/// does not). Returns `(child_ttbr0_pa, pages_copied)`.
1039	+///
1040	+/// On failure the partial child is unwound — its leaves freed, its tree
1041	+/// destroyed — so an out-of-memory fork leaks nothing.
1042	+fn copy_addrspace(parent_ttbr0: u64) -> Result<(u64, u64), MapError> {
1043	+    let mut child = AddrSpace::new()?;
1044	+    let mut pages: u64 = 0;
1045	+
1046	+    let result = walk_leaves(parent_ttbr0, &mut |va, pa, prot| {
1047	+        let frame = alloc_frame().ok_or(MapError::OutOfMemory)?;
1048	+        let new_pa = frame.addr();
1049	+        // SAFETY: both PAs came from the frame allocator, so both are
1050	+        // HHDM-mapped, 4 KiB-aligned, and distinct (copy_nonoverlapping's
1051	+        // contract). Single-threaded EL1 context.
1052	+        unsafe {
1053	+            core::ptr::copy_nonoverlapping(
1054	+                phys_to_hhdm(pa) as *const u8,
1055	+                phys_to_hhdm(new_pa),
1056	+                FRAME_SIZE,
1057	+            );
1058	+        }
1059	+        if prot.executable {
1060	+            // SAFETY: the HHDM alias of `new_pa` is a valid EL1-readable
1061	+            // mapping of the just-written range (same pattern as
1062	+            // `userland::build_stub`'s blob install).
1063	+            unsafe { flush_icache_range(phys_to_hhdm(new_pa) as u64, FRAME_SIZE) };
1064	+        }
1065	+        child.map_page(va, new_pa, prot)?;
1066	+        pages += 1;
1067	+        Ok(())
1068	+    });
1069	+
1070	+    match result {
1071	+        Ok(()) => Ok((child.ttbr0_pa, pages)),
1072	+        Err(e) => {
1073	+            // Unwind: free the pages the partial copy installed, then the
1074	+            // tree. The child never had an ASID, so there is nothing to
1075	+            // flush or recycle.
1076	+            let _ = walk_leaves(child.ttbr0_pa, &mut |_va, pa, _prot| {
1077	+                free_frame(Frame::from_addr(pa));
1078	+                Ok(())
1079	+            });
1080	+            child.destroy();
1081	+            Err(e)
1082	+        }
1083	+    }
1084	+}
