1086	+/// The child's name: the parent's with `*F` appended when there is room
1087	+/// (MINIX 3 do_fork.c parity — `name[0]` keeps the parent's letter so traces
1088	+/// stay readable).
1089	+fn fork_name(
1090	+    mut name: [u8; crate::proc::proc_struct::PROC_NAME_LEN],
1091	+) -> [u8; crate::proc::proc_struct::PROC_NAME_LEN] {
1092	+    let len = name.iter().position(|&b| b == 0).unwrap_or(name.len());
1093	+    if len + 2 < name.len() {
1094	+        name[len] = b'*';
1095	+        name[len + 1] = b'F';
1096	+    }
1097	+    name
1098	+}
