76	/// Map a [`ProcNr`] to its index in the process table.
77	///
78	/// Kernel tasks (negative `nr`) land in slots `[0, NR_TASKS)`; user processes
79	/// land in `[NR_TASKS, N_PROC_SLOTS)`. Returns `None` if `nr` is outside the
80	/// allocated range.
81	pub const fn proc_index(nr: ProcNr) -> Option<usize> {
82	    let n = nr.get();
83	    let shifted = n + NR_TASKS as i32;
84	    if shifted < 0 || (shifted as usize) >= N_PROC_SLOTS {
85	        None
86	    } else {
87	        Some(shifted as usize)
88	    }
89	}
