91	/// Resolve a user-supplied endpoint to its process-table index, verifying the
92	/// slot is allocated and its stored endpoint — generation included — matches.
93	/// MINIX 3 `kernel/system.c` `isokendpt`/`okendpt`.
94	///
95	/// Once slots recycle (slice 4.6: `SYS_EXIT` bumps the generation on free,
96	/// `SYS_FORK` reuses the slot), a bare `proc_index(endpoint_proc(e))` would
97	/// silently resolve a stale endpoint to the slot's *new* occupant. Every path
98	/// that translates an endpoint taken from a message or trap register must go
99	/// through here; kernel-originated deliveries that hold live `ProcNr`s
100	/// (`mini_pf_send`, `deliver_alarm`, …) don't.
101	///
102	/// Errors: `EBADSRCDST` for an out-of-range proc field, `EDEADSRCDST` for a
103	/// freed slot or generation mismatch.
104	pub fn okendpt(proc_table: &[Proc; N_PROC_SLOTS], e: Endpoint) -> Result<usize, i32> {
105	    let Some(idx) = proc_index(endpoint_proc(e)) else {
106	        return Err(EBADSRCDST);
107	    };
108	    let p = &proc_table[idx];
109	    if p.rts_flags.load(core::sync::atomic::Ordering::Relaxed) & RTS_SLOT_FREE != 0
110	        || p.endpoint != e
111	    {
112	        return Err(EDEADSRCDST);
113	    }
114	    Ok(idx)
115	}
