272	        priv_flags: SYS_PROC | PREEMPTIBLE,
273	        trap_mask: SRV_T,
274	        priority: SRV_Q,
275	        quantum_ms: SRV_QUANTUM_MS,
276	        runnable: false,
277	    },
278	    BootEntry {
279	        nr: INIT_PROC_NR,
280	        name: b"init",
281	        priv_flags: SYS_PROC | PREEMPTIBLE,
282	        trap_mask: SRV_T,
283	        priority: INIT_Q,
284	        quantum_ms: SRV_QUANTUM_MS,
285	        runnable: false,
286	    },
287	];
288	
289	// ---------------------------------------------------------------------------
290	// Access helpers. All return raw pointers — callers carry the single-threaded
291	// invariant.
292	// ---------------------------------------------------------------------------
293	
294	/// SAFETY: caller must ensure no other reference into `PROC_TABLE` exists.
295	pub(crate) unsafe fn proc_slot_mut(nr: ProcNr) -> Option<&'static mut Proc> {
296	    let idx = proc_index(nr)?;
297	    // SAFETY: `idx` is in-range; single-threaded boot context.
298	    let arr = unsafe { &mut *PROC_TABLE.0.get() };
299	    Some(&mut arr[idx])
300	}
301	
302	/// SAFETY: caller must ensure no exclusive reference into `PROC_TABLE` exists.
303	pub(crate) unsafe fn proc_table_ref() -> &'static [Proc; N_PROC_SLOTS] {
304	    // SAFETY: single-threaded boot context.
305	    unsafe { &*PROC_TABLE.0.get() }
306	}
307	
308	/// Borrow `PROC_TABLE` mutably as a slice. Used by `ipc::do_ipc` to hand a
309	/// single `&mut [Proc]` down through every IPC primitive — avoiding the
310	/// two-`&mut`-from-one-`UnsafeCell` hazard that arises if each primitive
311	/// re-borrows individual slots via `proc_slot_mut`.
312	///
313	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
314	/// invariant and must not hold any other reference into `PROC_TABLE`
315	/// while the returned borrow is live.
316	pub(crate) unsafe fn proc_table_mut_slice() -> &'static mut [Proc; N_PROC_SLOTS] {
317	    // SAFETY: forwarded — caller's invariants.
318	    unsafe { &mut *PROC_TABLE.0.get() }
319	}
320	
321	/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
322	pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
323	    let idx = priv_index(id)?;
324	    // SAFETY: `idx` is in-range; single-threaded boot context.
325	    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
326	    Some(&mut arr[idx])
327	}
328	
329	/// SAFETY: caller must ensure no exclusive reference into `PRIV_TABLE` exists.
330	pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
331	    // SAFETY: single-threaded boot context.
332	    unsafe { &*PRIV_TABLE.0.get() }
333	}
334	
335	/// Borrow `PRIV_TABLE` mutably as a slice. Companion of
336	/// [`proc_table_mut_slice`] — `ipc::do_ipc` materializes both at once and
337	/// passes them down to the per-primitive handlers.
338	///
339	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
340	/// invariant and must not hold any other reference into `PRIV_TABLE`
341	/// while the returned borrow is live.
342	pub(crate) unsafe fn priv_table_mut_slice() -> &'static mut [Priv; NR_SYS_PROCS] {
343	    // SAFETY: forwarded — caller's invariants.
344	    unsafe { &mut *PRIV_TABLE.0.get() }
345	}
346	
347	// ---------------------------------------------------------------------------
348	// Boot-time population.
349	// ---------------------------------------------------------------------------
350	
351	/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
352	///
353	/// Called exactly once from `kmain` during boot. Slice 2.4's scheduler will
354	/// assume one-shot init; double-calling would clobber any RTS bits the
355	/// scheduler has set since.
356	pub fn init() {
357	    init_empty_slots();
358	    init_boot_image();
359	    populate_user_priv();
360	}
361	
362	/// Shared privilege slot for ordinary user processes (slice 4.5) — MINIX 3's
363	/// single user priv (`USER_PRIV_ID`), minus the dynamic id allocation. The
364	/// boot image occupies priv slots `[0, 16)` and the demo stubs are
365	/// kernel-installed at 16..=19 (`arch::aarch64::userland`); 20 is the next
366	/// free slot. `SYS_PRIVCTL(PRIVCTL_SET_USER)` points a frozen target here,
367	/// and the 4.6 fork path hands every forked child this same slot so fork
368	/// can't exhaust the 64-slot `PRIV_TABLE`.
369	pub(crate) const USER_PRIV_ID: PrivId = PrivId::new(20);
370	
371	const _: () = assert!((USER_PRIV_ID.get() as usize) < NR_SYS_PROCS);
372	
373	/// Populate the shared USER priv slot (slice 4.5).
374	///
375	/// `USR_T` traps (SENDREC only), `ipc_to` open to PM alone, and an *empty*
376	/// kernel-call mask — ordinary user processes make no kernel calls (MINIX 3
377	/// `table.c` gives the user template a `{0}` call mask). `sig_mgr` is PM:
378	/// MINIX makes PM the signal manager for user processes, while the boot
379	/// slots keep RS (the system-process manager) from `populate_priv`.
380	///
381	/// Also opens the reverse PM → USER `ipc_to` bit so PM can reply to a user
382	/// proc's SENDREC — `init_boot_image` fills SRV_T bitmaps only for the active
383	/// boot slots `[0, n_active)`, the same gap `install_stub_d_priv` closes for
384	/// VM → D (as a second, sequential borrow).
385	fn populate_user_priv() {
386	    let pm_priv_id = {
387	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
388	        let table = unsafe { proc_table_ref() };
389	        let idx = proc_index(PM_PROC_NR).expect("PM in proc table");
390	        table[idx].priv_id.expect("PM priv populated by proc::init")
391	    };
392	
393	    {
394	        // SAFETY: priv index < NR_SYS_PROCS (const-asserted); single-threaded
395	        // boot context; no overlapping reference into PRIV_TABLE held.
396	        let pr = unsafe { priv_slot_mut(USER_PRIV_ID) }.expect("USER priv slot in range");
397	        pr.id = USER_PRIV_ID;
398	        // Shared among every USER-priv proc — no single owning proc.
399	        pr.proc_nr = None;
400	        pr.flags = PREEMPTIBLE | BILLABLE;
401	        pr.trap_mask = USR_T;
402	        pr.ipc_to.fill(0);
403	        set_sys_bit(&mut pr.ipc_to, pm_priv_id);
404	        pr.k_call_mask.fill(0);
405	        pr.notify_pending.fill(0);
406	        pr.asyn_pending.fill(0);
407	        pr.sig_mgr = boot_endpoint(PM_PROC_NR);
408	    }
409	
410	    // Open PM → USER. Separate borrow: the USER slot's `&mut Priv` above has
411	    // been dropped.
412	    {
413	        // SAFETY: priv index in-range; no overlapping reference held.
414	        let pm_pr = unsafe { priv_slot_mut(pm_priv_id) }.expect("PM priv slot in range");
415	        set_sys_bit(&mut pm_pr.ipc_to, USER_PRIV_ID);
416	    }
417	}
418	
419	fn init_empty_slots() {
420	    // Give every slot a valid (nr, endpoint) so that index-based traversal
421	    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
422	    for i in 0..N_PROC_SLOTS {
423	        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
424	        // SAFETY: index in-range; single-threaded boot context; no other
425	        // references into PROC_TABLE exist at this point in `init`.
426	        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
427	        p.nr = nr;
428	        p.endpoint = boot_endpoint(nr);
429	        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
430	    }
431	
432	    for i in 0..NR_SYS_PROCS {
433	        // SAFETY: index in-range; single-threaded boot context.
434	        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }.expect("priv index in range");
435	        pr.id = PrivId::new(i as u16);
436	    }
437	}
438	
439	fn init_boot_image() {
440	    // Active priv-slot count after population — the IPC bitmap for SRV_T
441	    // entries needs to enumerate every active slot.
442	    let n_active = N_IMAGE as u16;
443	
444	    for (slot, entry) in IMAGE.iter().enumerate() {
445	        let priv_id = PrivId::new(slot as u16);
446	        populate_priv(priv_id, entry, n_active);
447	        populate_proc(priv_id, entry);
448	    }
449	}
450	
451	fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
452	    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
453	    // overlapping reference into PRIV_TABLE held across the call.
454	    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
455	    pr.id = id;
456	    pr.proc_nr = Some(entry.nr);
457	    pr.flags = entry.priv_flags;
458	    pr.trap_mask = entry.trap_mask;
459	
460	    if entry.trap_mask == SRV_T {
461	        // SRV_T privs can send to every active slot. Set bits [0, n_active).
462	        fill_bits(&mut pr.ipc_to, n_active as usize);
463	        // SRV_T privs can issue every kernel call defined so far. This bound
464	        // tracks the highest `SYS_*` number; slice 4.3 widened it to admit
465	        // `SYS_SCHEDULE` / `SYS_SCHEDCTL` so SCHED may issue them.
466	        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE4);
467	    }
468	    // Kernel-task slots leave ipc_to and k_call_mask zeroed.
469	
470	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
471	    pr.notify_pending.fill(0);
472	    pr.asyn_pending.fill(0);
473	}
474	
475	fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
476	    // SAFETY: proc index in-range; single-threaded boot context; no
477	    // overlapping reference into PROC_TABLE held across the call.
478	    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
479	    p.priv_id = Some(priv_id);
480	    p.priority = entry.priority;
481	    p.quantum_ms = entry.quantum_ms;
482	    p.quantum_left = entry.quantum_ms as u64;
483	    p.endpoint = boot_endpoint(entry.nr);
484	    p.nr = entry.nr;
485	    // Boot procs start kernel-scheduled; a user-space scheduler claims them
486	    // later via `SYS_SCHEDCTL` (slice 4.3). `Proc::EMPTY` already zeroes this to
487	    // `NONE`, but set it explicitly so a future slot-reuse path can't inherit a
488	    // stale scheduler endpoint.
489	    p.scheduler = NONE;
490	
491	    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
492	    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
493	    p.name[..n].copy_from_slice(&entry.name[..n]);
494	    p.name[n..].fill(0);
495	
496	    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
497	    p.rts_flags
498	        .store(rts, core::sync::atomic::Ordering::Relaxed);
499	}
500	
501	/// Set the lowest `n` bits in a `u32` bitmap.
502	fn fill_bits(map: &mut [u32], n: usize) {
503	    for i in 0..n {
504	        let word = i / 32;
505	        let bit = i % 32;
506	        if word < map.len() {
507	            map[word] |= 1 << bit;
508	        }
509	    }
510	}
511	
512	// Compile-time sanity that the bitmap sizing came out as expected.
513	const _: () = assert!(IPC_MAP_CHUNKS == 2);
514	const _: () = assert!(K_CALL_MASK_CHUNKS == 1);
515	
516	/// Number of slots in `PROC_TABLE` (for the dump helper).
517	pub const fn n_proc_slots() -> usize {
518	    N_PROC_SLOTS
519	}
520	
521	/// Number of slots in `IMAGE` (for the dump helper).
522	pub const fn n_image_slots() -> usize {
523	    N_IMAGE
524	}
525

